import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,e as s}from"./app-a3db62c9.js";const r={},i=s(`<h1 id="面试-spring" tabindex="-1"><a class="header-anchor" href="#面试-spring" aria-hidden="true">#</a> 面试-Spring</h1><h3 id="对spring的理解" tabindex="-1"><a class="header-anchor" href="#对spring的理解" aria-hidden="true">#</a> 对Spring的理解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：对Spring的理解</b></summary><p><b style="color:#f19977;">答：Spring核心思想为IOC、DI、AOP。Spring框架使用了Java里面的反射机制。IOC就是把对象的创建控制权转移到IOC容器并且负责对象的创建、初始化等一系列工作。被创建的对象在IOC容器中称为Bean。在容器中建立Bean与Bean之间的关系就称为依赖注入。AOP底层是代理模式，可以在不改变原有代码结构的情况下增强功能。具体操作核心是先定义切面来封装通用逻辑，再通过切点明确要切入的目标方法(如指定包 / 类 / 方法规则)，接着定义通知确定增强逻辑的执行时机(前置 / 后置 / 环绕 / 异常 / 最终)。</b></p></details><h3 id="spring的二种注入方式" tabindex="-1"><a class="header-anchor" href="#spring的二种注入方式" aria-hidden="true">#</a> Spring的二种注入方式</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring的二种注入方式</b></summary><p><b style="color:#f19977;">答：setter方式和构造方法的方式</b></p></details><h3 id="aop有哪些应用场景" tabindex="-1"><a class="header-anchor" href="#aop有哪些应用场景" aria-hidden="true">#</a> AOP有哪些应用场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：AOP有哪些应用场景</b></summary><p><b style="color:#f19977;">答：事务管理、日志打印。</b></p></details><h3 id="spring中的事务是如何实现的" tabindex="-1"><a class="header-anchor" href="#spring中的事务是如何实现的" aria-hidden="true">#</a> Spring中的事务是如何实现的</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring中的事务是如何实现的</b></summary><p><b style="color:#f19977;">答：Spring支持编程式事务和声明式事务两种方式。一般使用声明式事务即在方法上加入@Transactional注解</b></p></details><h3 id="spring事务失效场景" tabindex="-1"><a class="header-anchor" href="#spring事务失效场景" aria-hidden="true">#</a> Spring事务失效场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring事务失效场景</b></summary><p><b style="color:#f19977;">答：1. 异常捕获并自己处理了并没有抛出异常<br>2. 抛出检查异常(throws xxxException)，可以为@Transactional配置rollbackFor属性，@Transactional(rollbackFor=Exception.class)<br>3. 非public方法导致事务失效<br>4. 同类内部调用(this)：原因是用this没有走代理，用的是原生对象</b></p></details><h3 id="autowired-和-resource的区别" tabindex="-1"><a class="header-anchor" href="#autowired-和-resource的区别" aria-hidden="true">#</a> @Autowired 和@Resource的区别?</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：@Autowired 和@Resource 的区别?</b></summary><p><b style="color:#f19977;">答：@Autowired是按照类型进行注入其属于Spring框架注解。@Resource会按照名称注入，名称找不着会按照类型来找其属于JDK自带注解。</b></p></details><h3 id="为什么bean要设计成单例" tabindex="-1"><a class="header-anchor" href="#为什么bean要设计成单例" aria-hidden="true">#</a> 为什么Bean要设计成单例</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：为什么Bean要设计成单例</b></summary><p><b style="color:#f19977;">答：资源利用效率：单例模式可以节省系统资源，避免重复创建和销毁对象。当一个对象被多次请求时，只需要创建一次实例并重复使用，提高了系统的资源利用效率。对象一致性：对于某些需要保持一致状态或共享数据的对象，使用单例模式可以确保全局只有一个实例。这样可以避免多个实例之间的数据不一致性问题，简化了数据管理和同步的复杂性。全局访问性：单例模式使得对象在整个应用程序的上下文中可被访问。这对于需要在不同的组件或模块中共享数据或提供共享服务的对象非常有用。配置和管理简便性：在Spring框架中，Bean的单例模式使得对象的创建、依赖注入和生命周期管理更加简便。通过Spring容器的管理，可以统一配置和管理Bean的创建和销毁过程。</b></p></details><h3 id="spring中bean的生命周期" tabindex="-1"><a class="header-anchor" href="#spring中bean的生命周期" aria-hidden="true">#</a> Spring中Bean的生命周期</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring中Bean的生命周期</b></summary><p><b style="color:#f19977;">答：通过BeanDefinition获取Bean的定义信息<br>调用构造函数实例化Bean<br>Bean的依赖注入<br>处理Aware接口<br>Bean的后置处理器BeanPostProcessor-前置<br>初始化方法<br>Bean的后置处理器BeanPostProcessor-后置<br>销毁Bean</b></p></details><h3 id="bean是线程安全的吗" tabindex="-1"><a class="header-anchor" href="#bean是线程安全的吗" aria-hidden="true">#</a> Bean是线程安全的吗</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Bean是线程安全的吗</b></summary><p><b style="color:#f19977;">答：如果这个Bean里有成员变量则不是线程安全的，除非这个成员变量自身是线程安全的。</b></p></details><h3 id="spring解决循环依赖" tabindex="-1"><a class="header-anchor" href="#spring解决循环依赖" aria-hidden="true">#</a> Spring解决循环依赖</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring解决循环依赖</b></summary><p><b style="color:#f19977;">答：循环依赖就是两个Bean互相依赖对方最终形成闭环，比如A依赖B，B依赖A。Spring解决通过setter方式注入的循环依赖问题是通过三级缓存。<br>一级缓存：缓存完整的Bean对象<br>二级缓存：缓存Bean对象的半成品<br>三级缓存：缓存Bean对象的工厂对象<br>解决构造方法依赖注入的方式是使用@Lazy注解进行懒加载，什么时候需要对象再进行Bean的创建</b></p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token class-name">A</span><span class="token punctuation">(</span><span class="token annotation punctuation">@Lazy</span> <span class="token class-name">B</span> b<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;A的构造方法执行了...&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>b <span class="token operator">=</span> b<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="jdk代理和cglib代理使用场景" tabindex="-1"><a class="header-anchor" href="#jdk代理和cglib代理使用场景" aria-hidden="true">#</a> JDK代理和CGLIB代理使用场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：JDK代理和CGLIB代理使用场景</b></summary><p><b style="color:#f19977;">答：目标类实现了接口用JDK动态代理<br>没有接口用CGLIB代理</b></p></details><h3 id="spring事务传播机制" tabindex="-1"><a class="header-anchor" href="#spring事务传播机制" aria-hidden="true">#</a> Spring事务传播机制</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring事务传播机制</b></summary><p><b style="color:#f19977;">答：required：有事务则加入，没有则创建(默认行为)<br>requires_new：无论有无事务，都新建独立事务<br>supports：有事务则加入，无事务则非事务运行<br>mandatory：必须在事务内运行，无事务抛出异常<br>not_supported：始终非事务运行，有事务则挂起<br>never：必须在非事务内运行，有事务抛出异常<br>nested：外层有事务则嵌套执行，无事务则新建事务</b></p></details><h3 id="spring事务是如何和数据库连接绑定的" tabindex="-1"><a class="header-anchor" href="#spring事务是如何和数据库连接绑定的" aria-hidden="true">#</a> Spring事务是如何和数据库连接绑定的</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring事务是如何和数据库连接绑定的</b></summary><p><b style="color:#f19977;">答：Spring事务通过ThreadLocal把数据库连接绑定到当前线程，实现事务与连接的绑定事务开启时，从数据源获取连接，放入ThreadLocal缓存，不再释放回连接池。同一线程内的所有DAO操作，都从ThreadLocal取同一个连接，共用同一事务，事务提交 / 回滚后，连接才释放并归还连接池，同时清空ThreadLocal。多线程环境下互不干扰，每个线程持有独立连接，实现事务隔离。</b></p></details><h3 id="beanfactory和factorybean" tabindex="-1"><a class="header-anchor" href="#beanfactory和factorybean" aria-hidden="true">#</a> BeanFactory和FactoryBean</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：BeanFactory和FactoryBean</b></summary><p><b style="color:#f19977;">答：BeanFactory：是Spring的Bean容器顶层接口，负责加载、创建、管理 Bean<br>FactoryBean：是一个能生产Bean对象的工厂Bean，通过getObject()返回实例，可定制复杂Bean创建逻辑</b></p></details><h3 id="configuration和-component区别" tabindex="-1"><a class="header-anchor" href="#configuration和-component区别" aria-hidden="true">#</a> @Configuration和@Component区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：@Configuration和@Component区别</b></summary><p><b style="color:#f19977;">答：@Configuration本质是@Component的增强版，用于声明配置类@Configuration会被CGLIB代理，调用内部@Bean方法是单例。@Component不会代理，多次调用会新建新对象。</b></p></details><h3 id="spring中常用注解" tabindex="-1"><a class="header-anchor" href="#spring中常用注解" aria-hidden="true">#</a> Spring中常用注解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring中常用注解</b></summary><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>@Component
@Controller
@Service
@Repository
@Autowired
@Qualifier
@Scope
@Configuration
@ComponentScan
@Bean
@Import
@Aspect
@Before
@After
@Around
@Pointcut
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="springmvc中常用注解" tabindex="-1"><a class="header-anchor" href="#springmvc中常用注解" aria-hidden="true">#</a> SpringMVC中常用注解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：SpringMVC中常用注解</b></summary><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>@RequestMapping
@RequestBody
@RequestParam
@PathViriable
@ResponseBody
@RequestHeader
@RestController
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="拦截器与过滤器" tabindex="-1"><a class="header-anchor" href="#拦截器与过滤器" aria-hidden="true">#</a> 拦截器与过滤器</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：拦截器与过滤器</b></summary><p><b style="color:#f19977;">答：过滤器(Filter)：Servlet规范，它能拦截所有进入应用的请求和响应，比如静态资源、登录访问等，它可以修改请求和响应，但无法访问Spring容器内部的Bean。<br>拦截器(Interceptor)：SpringMVC框架自带，作用于Spring容器内部，它只拦截Controller层方法，可以完全访问Spring的上下文，比如获取Bean，处理业务逻辑等。所以在做登录校验、日志记录或权限控制时倾向于使用拦截器。</b></p></details>`,37),t=[i];function l(o,d){return e(),n("div",null,t)}const p=a(r,[["render",l],["__file","面试-Spring.html.vue"]]);export{p as default};
